import React, { useState, useRef } from "react";

export default function LoginPage() {
  const [showPassword, setShowPassword] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [focusedInput, setFocusedInput] = useState(null);
  const [rememberMe, setRememberMe] = useState(false);
  const [rotateX, setRotateX] = useState(0);
  const [rotateY, setRotateY] = useState(0);
  const cardRef = useRef(null);

  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const mouseX = e.clientX - centerX;
    const mouseY = e.clientY - centerY;

    const maxRotate = 10;
    const rotateYValue = (mouseX / (rect.width / 2)) * maxRotate;
    const rotateXValue = (mouseY / (rect.height / 2)) * -maxRotate;

    setRotateY(rotateYValue);
    setRotateX(rotateXValue);
  };

  const handleMouseLeave = () => {
    setRotateX(0);
    setRotateY(0);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setIsLoading(true);
    setTimeout(() => setIsLoading(false), 2000);
  };

  return (
    <div className="login-container">
      {/* خلفية أرجوانية غامقة متدرجة إلى الأسود */}
      <div className="bg-gradient"></div>

      <div className="noise-overlay"></div>
      <div className="glow-spot-1"></div>
      <div className="glow-spot-2"></div>

      <div className="card-wrapper">
        <div
          ref={cardRef}
          className="login-card"
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
          style={{
            transform: `perspective(1500px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`,
            transition: "transform 0.1s ease-out"
          }}
        >
          <div className="card-content">
            <div className="logo">
              <span>S</span>
            </div>

            <h1 className="title">Welcome Back</h1>
            <p className="subtitle">Sign in to continue to StyleMe</p>

            <form onSubmit={handleSubmit}>
              <div className="input-group">
                <div className={`input-wrapper ${focusedInput === "email" ? "focused" : ""}`}>
                  <input
                    type="email"
                    placeholder="Email address"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    onFocus={() => setFocusedInput("email")}
                    onBlur={() => setFocusedInput(null)}
                  />
                </div>
              </div>

              <div className="input-group">
                <div className={`input-wrapper ${focusedInput === "password" ? "focused" : ""}`}>
                  <input
                    type={showPassword ? "text" : "password"}
                    placeholder="Password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    onFocus={() => setFocusedInput("password")}
                    onBlur={() => setFocusedInput(null)}
                  />
                  <button type="button" className="password-toggle" onClick={() => setShowPassword(!showPassword)}>
                    {showPassword ? "👁️" : "👁️‍🗨️"}
                  </button>
                </div>
              </div>

              <div className="options-row">
                <label className="checkbox-label">
                  <input type="checkbox" checked={rememberMe} onChange={() => setRememberMe(!rememberMe)} />
                  <span>Remember me</span>
                </label>
                <a href="#" className="forgot-link">Forgot password?</a>
              </div>

              <button type="submit" className="signin-btn" disabled={isLoading}>
                {isLoading ? "Loading..." : "Sign In"}
              </button>

              <p className="signup-link">
                Don't have an account? <a href="#">Sign up</a>
              </p>
            </form>
          </div>
        </div>
      </div>

      <style>{`
        * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
        }

        .login-container {
          min-height: 100vh;
          width: 100%;
          position: relative;
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        }

        /* خلفية أرجوانية غامقة متدرجة إلى الأسود */
        .bg-gradient {
          position: absolute;
          inset: 0;
          background: radial-gradient(ellipse at 50% 30%, 
            #2d1b4e 0%,
            #1a0b2e 40%,
            #0a0a0a 70%,
            #050505 100%
          );
          z-index: 0;
        }

        /* بقع متوهجة */
        .glow-spot-1 {
          position: absolute;
          left: 10%;
          top: 20%;
          width: 500px;
          height: 500px;
          background: radial-gradient(circle, rgba(139, 92, 246, 0.15), transparent 70%);
          border-radius: 50%;
          filter: blur(80px);
          animation: pulse 6s ease-in-out infinite;
          z-index: 0;
        }

        .glow-spot-2 {
          position: absolute;
          right: 10%;
          bottom: 20%;
          width: 500px;
          height: 500px;
          background: radial-gradient(circle, rgba(168, 85, 247, 0.12), transparent 70%);
          border-radius: 50%;
          filter: blur(80px);
          animation: pulse 6s ease-in-out infinite 3s;
          z-index: 0;
        }

        .noise-overlay {
          position: absolute;
          inset: 0;
          opacity: 0.03;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
          background-size: 200px 200px;
          pointer-events: none;
          z-index: 1;
        }

        @keyframes pulse {
          0%, 100% { opacity: 0.4; transform: scale(1); }
          50% { opacity: 0.8; transform: scale(1.1); }
        }

        .card-wrapper {
          position: relative;
          z-index: 10;
          width: 100%;
          max-width: 400px;
          margin: 0 20px;
        }

        .login-card {
          position: relative;
        }

        .card-content {
          position: relative;
          background: rgba(0, 0, 0, 0.55);
          backdrop-filter: blur(20px);
          border-radius: 24px;
          padding: 40px 32px;
          border: 1px solid rgba(255, 255, 255, 0.1);
          box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
        }

        .logo {
          width: 56px;
          height: 56px;
          margin: 0 auto 24px;
          border-radius: 50%;
          background: linear-gradient(135deg, rgba(139, 92, 246, 0.3), rgba(0, 0, 0, 0.5));
          border: 1px solid rgba(255, 255, 255, 0.2);
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .logo span {
          font-size: 28px;
          font-weight: bold;
          background: linear-gradient(135deg, #fff, #a855f7);
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
        }

        .title {
          text-align: center;
          font-size: 28px;
          font-weight: bold;
          color: white;
          margin-bottom: 8px;
        }

        .subtitle {
          text-align: center;
          font-size: 14px;
          color: rgba(255, 255, 255, 0.6);
          margin-bottom: 32px;
        }

        .input-group {
          margin-bottom: 20px;
        }

        .input-wrapper {
          position: relative;
          display: flex;
          align-items: center;
          background: rgba(255, 255, 255, 0.05);
          border-radius: 12px;
          transition: all 0.3s ease;
          border: 1px solid rgba(255, 255, 255, 0.1);
        }

        .input-wrapper.focused {
          background: rgba(255, 255, 255, 0.1);
          border-color: rgba(139, 92, 246, 0.5);
          box-shadow: 0 0 0 2px rgba(139, 92, 246, 0.2);
        }

        .input-wrapper input {
          width: 100%;
          padding: 14px 16px;
          background: transparent;
          border: none;
          color: white;
          font-size: 14px;
          outline: none;
        }

        .input-wrapper input::placeholder {
          color: rgba(255, 255, 255, 0.4);
        }

        .password-toggle {
          position: absolute;
